import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.ZhLefgN8.js";const c=JSON.parse('{"title":"港股交易规则与结算","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/trading-hours-and-rules/hk-trading-rules.md","filePath":"zh-CN/stock-trading/trading-hours-and-rules/hk-trading-rules.md"}'),h={name:"stock-trading/trading-hours-and-rules/hk-trading-rules.md"};function l(i,t,o,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="港股交易规则与结算" tabindex="-1">港股交易规则与结算 <a class="header-anchor" href="#港股交易规则与结算" aria-label="Permalink to &quot;港股交易规则与结算&quot;">​</a></h1><p>香港证券市场的交易时段、订单规则、T+2 交收机制及涨跌幅说明。</p><h2 id="交易时间" tabindex="-1">交易时间 <a class="header-anchor" href="#交易时间" aria-label="Permalink to &quot;交易时间&quot;">​</a></h2><p>除公众假日及因恶劣天气导致的休市外，香港证券市场一般在周一到周五进行交易。</p><h3 id="预开盘时段" tabindex="-1">预开盘时段 <a class="header-anchor" href="#预开盘时段" aria-label="Permalink to &quot;预开盘时段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时段</th><th>全日交易 &amp; 半日交易</th><th>交易规则</th></tr></thead><tbody><tr><td>输入买卖盘时段</td><td>09:00 - 09:15</td><td>可委托下单、改单、撤单</td></tr><tr><td>不可撤单时段</td><td>09:15 - 09:20</td><td>只可委托竞价限价单 (ALO) 和竞价市价单 (AO)，不可撤单、改单</td></tr><tr><td>随机对盘时段</td><td>09:20 - 不迟于 09:22</td><td>可委托下单，不可撤单、改单</td></tr><tr><td>暂停时段</td><td>对盘完成后 - 09:30</td><td>不可委托下单、改单、撤单</td></tr></tbody></table><p>半日交易适用于圣诞节、新年及农历新年前夕。</p><h3 id="持续交易时段" tabindex="-1">持续交易时段 <a class="header-anchor" href="#持续交易时段" aria-label="Permalink to &quot;持续交易时段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时段</th><th>全日交易</th><th>半日交易</th><th>交易规则</th></tr></thead><tbody><tr><td>早市</td><td>09:30 - 12:00</td><td>09:30 - 12:00</td><td>可委托下单、改单、撤单，支持增强限价单 (ELO)</td></tr><tr><td>中午休市</td><td>12:00 - 13:00</td><td>—</td><td>可撤单、改单；早市未成交订单 12:30 后可撤单</td></tr><tr><td>午市</td><td>13:00 - 16:00</td><td>—</td><td>可委托下单、改单、撤单，支持增强限价单 (ELO)</td></tr></tbody></table><h3 id="收市竞价交易时段" tabindex="-1">收市竞价交易时段 <a class="header-anchor" href="#收市竞价交易时段" aria-label="Permalink to &quot;收市竞价交易时段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时段</th><th>全日交易</th><th>半日交易</th><th>交易规则</th></tr></thead><tbody><tr><td>收市竞价</td><td>16:00 - 16:01</td><td>12:00 - 12:01</td><td>计算及公布参考价，不可委托下单</td></tr><tr><td>输入买卖盘</td><td>16:01 - 16:06</td><td>12:01 - 12:06</td><td>可委托 ALO 和 AO、改单、撤单，价格限制不超出参考价 ±5%</td></tr><tr><td>不可撤单</td><td>16:06 - 16:08</td><td>12:06 - 12:08</td><td>可委托 ALO 和 AO，不可撤单改单，价格须在最低沽盘价与最高买盘价之间</td></tr><tr><td>随机收市</td><td>16:08 - 16:10</td><td>12:08 - 12:10</td><td>可委托 ALO 和 AO，不可撤单改单</td></tr></tbody></table><h2 id="交易与交收机制" tabindex="-1">交易与交收机制 <a class="header-anchor" href="#交易与交收机制" aria-label="Permalink to &quot;交易与交收机制&quot;">​</a></h2><h3 id="日内交易" tabindex="-1">日内交易 <a class="header-anchor" href="#日内交易" aria-label="Permalink to &quot;日内交易&quot;">​</a></h3><p>日内交易（Day Trade）是指在同一交易日内对某只股票的头寸进行买入卖出，也称 T+0 交易。长桥账户可以进行无限次日内交易。</p><h3 id="卖空规则" tabindex="-1">卖空规则 <a class="header-anchor" href="#卖空规则" aria-label="Permalink to &quot;卖空规则&quot;">​</a></h3><p>暂不支持港股卖空。</p><h3 id="清算规则" tabindex="-1">清算规则 <a class="header-anchor" href="#清算规则" aria-label="Permalink to &quot;清算规则&quot;">​</a></h3><p>港股实行 T+2 交割制度，即交易发生后第二个工作日才能完成清算交割。</p><h3 id="最小交易单位与涨跌幅" tabindex="-1">最小交易单位与涨跌幅 <a class="header-anchor" href="#最小交易单位与涨跌幅" aria-label="Permalink to &quot;最小交易单位与涨跌幅&quot;">​</a></h3><p>港股最小交易单位为 1 手，不足一手的股票为碎股。没有单日涨跌幅限制。</p><h3 id="股票价格最小变动单位" tabindex="-1">股票价格最小变动单位 <a class="header-anchor" href="#股票价格最小变动单位" aria-label="Permalink to &quot;股票价格最小变动单位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>股票价格（HKD）</th><th>最小变动单位（HKD）</th></tr></thead><tbody><tr><td>0.01 - 0.25</td><td>0.001</td></tr><tr><td>0.25 - 0.50</td><td>0.005</td></tr><tr><td>0.50 - 10.00</td><td>0.01</td></tr><tr><td>10.00 - 20.00</td><td>0.02</td></tr><tr><td>20.00 - 100.00</td><td>0.05</td></tr><tr><td>100.00 - 200.00</td><td>0.10</td></tr><tr><td>200.00 - 500.00</td><td>0.20</td></tr><tr><td>500.00 - 1,000.00</td><td>0.50</td></tr><tr><td>1,000.00 - 2,000.00</td><td>1.00</td></tr><tr><td>2,000.00 - 5,000.00</td><td>2.00</td></tr><tr><td>5,000.00 - 9,995.00</td><td>5.00</td></tr></tbody></table><h3 id="etf-价格最小变动单位" tabindex="-1">ETF 价格最小变动单位 <a class="header-anchor" href="#etf-价格最小变动单位" aria-label="Permalink to &quot;ETF 价格最小变动单位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>价格（HKD）</th><th>最小变动单位（HKD）</th></tr></thead><tbody><tr><td>0.01 - 1.00</td><td>0.001</td></tr><tr><td>1.00 - 5.00</td><td>0.002</td></tr><tr><td>5.00 - 10.00</td><td>0.005</td></tr><tr><td>10.00 - 20.00</td><td>0.01</td></tr><tr><td>20.00 - 100.00</td><td>0.02</td></tr><tr><td>100.00 - 200.00</td><td>0.05</td></tr><tr><td>200.00 - 500.00</td><td>0.10</td></tr><tr><td>500.00 - 1,000.00</td><td>0.20</td></tr><tr><td>1,000.00 - 2,000.00</td><td>0.50</td></tr><tr><td>2,000.00 - 9,999.00</td><td>1.00</td></tr></tbody></table><p>注意：买入超过 24 档、卖出超过 9 档可能会被拒绝。</p><h2 id="恶劣天气交易安排" tabindex="-1">恶劣天气交易安排 <a class="header-anchor" href="#恶劣天气交易安排" aria-label="Permalink to &quot;恶劣天气交易安排&quot;">​</a></h2><p>当天文台发出 8 号或以上热带气旋警告信号、黑色暴雨警告或香港政府公布极端情况时，港交所会启动恶劣天气交易安排。</p><p>自 2024 年 9 月 23 日起，恶劣天气下将维持交易、交易后及上市等运作，沪深港通、衍生产品假期交易和收市后交易时段可如常运作。具体安排请参考香港交易所网站。</p><p>恶劣天气期间：</p><ul><li>长桥办公室暂停对外开放，可通过线上客服或客服热线联系</li><li>不能提存实物股票，相关操作顺延</li><li>若恶劣天气全日维持，纸本支票顺延处理</li></ul><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading/订单类型/限价单与市价单">限价单与市价单</a> — ELO（增强限价单）、ALO（竞价限价单）和 AO（竞价市价单）详细规则</li></ul>',33)])])}const p=d(h,[["render",l]]);export{c as __pageData,p as default};
